import { runScenario } from "./scenario.js";

describe("MHPCO scenario engine", () => {
  // --- Edge case: empty policy ---
  it.todo("empty item list -> premium 5 G (only processing fee)");

  // --- Base premiums per item type (single item, 0-year customer, first quote) ---
  it.todo("single sword (steel, ench 3) -> 115 G (100 base + 10 first insurance + 5 fee)");
  it.todo("single amulet (silver, ench 0) -> 71 G (60 base + 6 first insurance + 5 fee)");
  it.todo("single staff (wood, ench 0) -> 93 G (80 base + 8 first insurance + 5 fee)");
  it.todo("single potion -> 49 G (40 base + 4 first insurance + 5 fee)");

  // --- Component pricing & block of 3 alike ---
  it.todo("2 runes -> 60 G (50 base + 5 first insurance + 5 fee)");
  it.todo("3 runes -> 71 G (60 base block + 6 first insurance + 5 fee)");
  it.todo("4 runes -> 115 G (100 base + 10 first insurance + 5 fee, no block)");
  it.todo("7 runes -> 198 G (175 base + 17.5 first insurance => 192.5 + 5 fee => round up to 198)");

  // --- 'Alike' components clarification ---
  it.todo("2 runes + 1 moonstone -> 88 G (75 base + 7.5 first insurance => 82.5 + 5 fee => 88)");
  it.todo("3 runes + 3 moonstones -> 137 G (120 base block+block + 12 first insurance + 5 fee)");

  // --- Modifier scope (per-item vs policy-wide) ---
  it.todo("policy with cursed sword + plain amulet (0 yrs, first quote) -> 231 G (160 base + 50 curse + 16 first + 5 fee)");

  // --- Modifier thresholds ---
  it.todo("customer with exactly 2 years (plain sword, first quote) -> 95 G (100 base - 20 loyalty + 10 first + 5 fee)");
  it.todo("sword with exactly enchantment 5 (0 yrs, first quote) -> 145 G (100 base + 30 high ench + 10 first + 5 fee)");
  it.todo("cursed sword with enchantment 5 (0 yrs, first quote) -> 195 G (100 + 50 curse + 30 high ench + 10 first + 5 fee)");
  it.todo("sword with enchantment 4, not cursed (0 yrs, first quote) -> 115 G (no surcharges)");

  // --- Integration examples ---
  it.todo("newcomer with cursed sword (steel, ench 3) -> 165 G");
  it.todo("long-standing customer 2nd quote, cursed sword (steel, ench 7) -> 160 G");

  // --- Rounding ---
  it.todo("premium with fraction is rounded up to whole G in MHPCO's favor");

  // --- Claim: standard reimbursement ---
  it.todo("steel sword (ench 3), damage 500 G -> payout 400 G");
  it.todo("rune damage 200 G -> payout 100 G");

  // --- Claim: high-enchantment clause ---
  it.todo("steel sword ench 9, damage 1000 G -> payout 400 G (50% then -100)");
  it.todo("dragon sword ench 8, damage 1000 G -> payout 400 G (high ench 50% wins, then -100)");

  // --- Claim: dragon material clause ---
  it.todo("dragon sword ench 5, damage 800 G -> payout 700 G (full reimbursement - 100 deductible)");
  it.todo("dragon sword ench 9, damage 1000 G -> payout 400 G (50% wins over full; 500 - 100)");

  // --- Claim: deductible per damage event ---
  it.todo("dragon attack damages sword (500) and amulet (300) -> payout 600 G (deductible per item)");

  // --- Claim: payout rounding (rounded down, MHPCO's favor) ---
  it.todo("payout calculation yielding fraction is rounded down to whole G");

  // --- Multiple items of the same type ---
  it.todo("policy with two swords -> insurance sum 2000 G, cap 4000 G (claim of 500 each = payout 800)");
  it.todo("dragon attack damages two swords (separate entries) -> each entry its own deductible");

  // --- Cap exhaustion ---
  it.todo("cursed sword (premium 165 G) -> cap 2000 G (based on unmodified insurance value)");
  it.todo("policy with sword + amulet -> insurance sum 1600 G, cap 3200 G");
  it.todo("policy with sword + 3 runes (block) -> insurance sum 1750 G, cap 3500 G (block discount only affects premium)");
  it.todo("sword cap 2000 G, two successive 1500 G claims -> 1400 then 600, remaining 600 then 0");

  // --- Invalid input (runScenario throws) ---
