type Item = { type: string };

type QuoteStep = { op: "quote"; items: Item[] };
type Step = QuoteStep;

type Scenario = {
  customer: { yearsWithMHPCO: number };
  steps: Step[];
};

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
};

const PROCESSING_FEE = 5;
const FIRST_INSURANCE_RATE = 0.1;

function premiumForItem(item: Item): number {
  return BASE_PREMIUMS[item.type] ?? 0;
}

function premiumForQuote(step: QuoteStep): number {
  const basePolicy = step.items.reduce((sum, item) => sum + premiumForItem(item), 0);
  const firstInsurance = basePolicy * FIRST_INSURANCE_RATE;
  return Math.ceil(basePolicy + firstInsurance) + PROCESSING_FEE;
}

export function runScenario(input: unknown): { results: unknown[] } {
  const scenario = input as Scenario;
  const results = scenario.steps.map((step) => ({ premium: premiumForQuote(step) }));
  return { results };
}

